import{C as e,o as n,c as l,a5 as i,E as h}from"./chunks/framework.CW28V7p_.js";const k=JSON.parse('{"title":"7. tmux","description":"","frontmatter":{},"headers":[],"relativePath":"module-0/7-tmux.md","filePath":"module-0/7-tmux.md","lastUpdated":1780937944000}'),p={name:"module-0/7-tmux.md"},c=Object.assign(p,{setup(d){const a={id:"m0-7-tmux",title:"🧠 Mini-check: tmux",intro:"3 питання — короткий quiz бо tmux простий.",questions:[{type:"scenario",q:"Ти запустила agave build (25 хв) на сервері через SSH. Через 10 хвилин у тебе пропав інтернет. Що станеться з build без tmux і що з tmux?",ideal:`БЕЗ tmux: build вб'ється з SIGHUP коли SSH session закриється. Все 10 хвилин компіляції пропали. Доведеться запускати заново.

З tmux: build продовжує працювати у background. tmux session відв'язана від SSH connection. Коли інтернет повернеться, можна reconnect через SSH і \`tmux attach -t build\` — побачити progress, який не зупинявся.

Це чому ВСІ довгі задачі (build, snapshot fetch, рестарт) треба робити у tmux.`,explanation:"Ключове: SIGHUP вбиває foreground process при SSH disconnect, tmux survive'ить бо attached process — це сам tmux server, not your bash. Якщо ти описала це + механіку attach після reconnect — повна відповідь."},{type:"command",q:'Як attach до існуючої tmux session з іменем "build"? Напиши команду.',accepts:["tmux attach -t build","tmux attach-session -t build","tmux a -t build"],ideal:"tmux attach -t build",explanation:"tmux attach -t <name> приєднується до session. -t специфікує target name (без -t — приєднується до останньої). Скорочення: tmux a (attach), tmux ls (list), tmux new -s name (new session). attach-session — повна форма attach."},{type:"mcq",q:"Яка комбінація клавіш detach (відключитися) з tmux session не вбиваючи її? (Default tmux prefix)",options:["Ctrl+B потім D","Ctrl+C","Ctrl+D","Ctrl+B потім X"],correct:[0],explanation:"Ctrl+B потім D = detach. Ctrl+B це tmux prefix (як escape key для tmux commands), потім D команда detach. Ctrl+C вб'є foreground process у session. Ctrl+D пошле EOF (зачинить shell). Ctrl+B потім X закриє pane."}]};return(r,s)=>{const t=e("Quiz");return n(),l("div",null,[s[0]||(s[0]=i("",49)),h(t,{data:a}),s[1]||(s[1]=i("",6))])}}});export{k as __pageData,c as default};
